  ["tips.tanker.master"] = "Tank-Attack\n|cffffffffMit diesem Kommando befiehlt man den gepanzerten Einheiten anzugreifen.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Tank-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.attack.master"] = "Attack-Control\n|cffffffffMit dieser Steuereinheit befiehlt man den Angriff.\nDie Option rechtsklicken um eine neue Standardaktion festzulegen.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Standardaktion auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.attack"] = "Attack\n|cffffffffMit diesem Kommando befiehlt man dem Raid oder der Party anzugreifen.|r\n\n|cffff0000Linksklicken um Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.ranged"] = "Ranged-Attack\n|cffffffffMit diesem Kommando befiehlt man den Fernkämpfern anzugreifen.|r\n\n|cffff0000Linksklicken um Ranged-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.melee"] = "Melee-Attack\n|cffffffffMit diesem Kommando befiehlt man den Nahkämpfern anzugreifen.|r\n\n|cffff0000Linksklicken um Melee-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.healer"] = "Healer-Attack\n|cffffffffMit diesem Kommando befiehlt man den Heilern anzugreifen.|r\n\n|cffff0000Linksklicken um Healer-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.dps"] = "DPS-Attack\n|cffffffffMit diesem Kommando befiehlt man der DPS anzugreifen.|r\n\n|cffff0000Linksklicken um DPS-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.attack.tank"] = "Tank-Attack\n|cffffffffMit diesem Kommando befiehlt man dem Tank anzugreifen.|r\n\n|cffff0000Linksklicken um Tank-Attack auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.mode.master"] = "Modus-Control\n|cffffffffMit dieser Steuereinheit kann man Kampfmodi ein- und ausschalten.\nDie Option Linksklicken um einen neuen Kampfmodus auszuwählen.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um den Kampfmodus zu wechseln|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.mode.passive"] = "Passiv-Modus\n|cffffffffIm Passiv-Modus greifen Einheiten keinen Gegner an.\nDieser Modus verhindert, dass der Tank in die Gegner läuft während ihr welche anlockt.\nDas Stay-Kommando hebt Passiv-Modus auf, in Kombination sollte Stay zuerst befohlen werden.\nDas Follow-Kommando hebt den Passiv-Modus auf, in Kombination sollte Follow zuerst befohlen werden.|r\n\n|cffff0000Linksklicken um den Passiv-Modus auszuwählen und auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.mode.grind"] = "Grind-Modus\n|cffffffffIm Grind-Modus greifen Einheiten eigenständig Gegner an.\nDieser Modus ermöglicht ein eigenständiges Level deiner Einheiten.|r\n\n|cffff0000Linksklicken um den Grind-Modus auszuwählen und auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.stallow.stay"] = "Stay|Follow\n|cffffffffMit dieser Schaltfläche gibt man den Befehl zum Stehen-Bleiben.\nDieses Kommando hebt den Passiv-Modus auf, in Kombination sollte Stay zuerst befohlen werden.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Stay auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.stallow.follow"] = "Stay|Follow\n|cffffffffMit dieser Schaltfläche gibt man den Befehl zum Folgen.\nDieses Kommando hebt den Passiv-Modus auf, in Kombination sollte Follow zuerst befohlen werden.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Follow auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.expand.stay"] = "Stay\n|cffffffffMit dieser Schaltfläche gibt man den Befehl zum Stehen-Bleiben.\nDieses Kommando hebt den Passiv-Modus auf, in Kombination sollte Stay zuerst befohlen werden.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Stay auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.expand.follow"] = "Follow\n|cffffffffMit dieser Schaltfläche gibt man den Befehl zum Folgen.\nDieses Kommando hebt den Passiv-Modus auf, in Kombination sollte Follow zuerst befohlen werden.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Follow auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.flee.master"] = "Flee-Control\n|cffffffffMit dieser Steuereinheit befiehlt man die Flucht.\nDie Option rechtsklicken um eine neue Standardaktion festzulegen.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Standardaktion auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.flee"] = "Flee\n|cffffffffMit diesem Kommando befiehlt man dem Raid oder der Party zu flüchten.|r\n\n|cffff0000Linksklicken um Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.ranged"] = "Ranged-Flee\n|cffffffffMit diesem Kommando befiehlt man den Fernkämpfern zu flüchten.|r\n\n|cffff0000Linksklicken um Ranged-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.melee"] = "Melee-Flee\n|cffffffffMit diesem Kommando befiehlt man den Nahkämpfern zu flüchten.|r\n\n|cffff0000Linksklicken um Melee-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.healer"] = "Healer-Flee\n|cffffffffMit diesem Kommando befiehlt man den Heilern zu flüchten.|r\n\n|cffff0000Linksklicken um Healer-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.dps"] = "DPS-Flee\n|cffffffffMit diesem Kommando befiehlt man der DPS zu flüchten.|r\n\n|cffff0000Linksklicken um DPS-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.tank"] = "Tank-Flee\n|cffffffffMit diesem Kommando befiehlt man den Tank zu flüchten.|r\n\n|cffff0000Linksklicken um Tank-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.flee.target"] = "Target-Flee\n|cffffffffMit diesem Kommando befiehlt man dem Ziel zu flüchten.|r\n\n|cffff0000Linksklicken um Target-Flee auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken zum Festlegen als Standardaktion|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.format.master"] = "Formation-Control\n|cffffffffMit dieser Steuereinheit kann man die Formation der Bots zu ändern.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um die aktuellen Formation abzurufen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.arrow"] = "Arrow-Formation\n|cffffffffDie Bots stellen sich in einer Pfeil-Formation auf.\nDie Blickrichtung der Bots entspricht der deinigen.\n\n1. Reihe Tanks\n2. Reihe Nahkämpfer\n3. Reihe Fernkämpfer\n4. Reihe Heiler|r\n\n|cffff0000Linksklicken um die Arrow-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.queue"] = "Queue-Formation\n|cffffffffDie Bots stellen sich in einer defensiven Formation auf.\nDie Blickrichtung der Bots entspricht der deinigen.|r\n\n|cffff0000Linksklicken um die Queue-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.near"] = "Near-Formation\n|cffffffffDie Bots stellen sich dicht nebeneinander auf.\nDie Blickrichtung der Bots entspricht der deinigen.|r\n\n|cffff0000Linksklicken um die Near-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.melee"] = "Melee-Formation\n|cffffffffDie Bots stellen sich für den Nahkampf auf.\nDie Blickrichtung der Bots entspricht der deinigen.|r\n\n|cffff0000Linksklicken um die Melee-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.line"] = "Line-Formation\n|cffffffffDie Bots stellen sich links und rechts von dir in einer Linie auf.\nDie Blickrichtung der Bots entspricht der deinigen.|r\n\n|cffff0000Linksklicken um die Line-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.circle"] = "Circle-Formation\n|cffffffffDie Bots stellen sich in einem Kreis um dich herum auf.\nDie Blickrichtung der Bots ist nach außen gereichtet.|r\n\n|cffff0000Linksklicken um die Circle-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.chaos"] = "Chaos-Formation\n|cffffffffJeder Bots folgt dir nach eigenem Ermessen.\nSie stellen sich völlig chaotisch auf.\nDie Blickrichtung ist vollkommen willkürlich.|r\n\n|cffff0000Linksklicken um die Chaos-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.format.shield"] = "Shield-Formation\n|cffffffffDie Bots stellen sich vor und neben dir auf.\nDie Blickrichtung der Bots entspricht der deinigen.|r\n\n|cffff0000Linksklicken um die Shield-Formation auszuwählen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.beast.master"] = "Beastmaster-Control\n|cffffffffDiese Steuereinheit ist für Mod-NPC-Beastmaster des Azerothcore.\nMod-NPC-Beastmaster erlaubt es jedem Character eine Bestie wie Jäger zu haben.\nDein Character kann die notwendigen Zauber bei 'White Fang' erlernen.\nDer GameMaster muss 'White Fang' in der Spielwelt platzieren.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.beast.release"] = "Bestie freilassen\n|cffffffffMit diesem Kommando kann man die Bestie freilassen.|r\n\n|cffff0000Linksklicken um die Bestie freizulassen|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.beast.revive"] = "Bestie wiederbeleben\n|cffffffffMit diesem Kommando kann man die Bestie wiederbeleben.|r\n\n|cffff0000Linksklicken um die Bestie wiederzubeleben|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.beast.heal"] = "Bestie heilen\n|cffffffffMit diesem Kommando kann man die Bestie heilen.|r\n\n|cffff0000Linksklicken um die Bestie zu heilen|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.beast.feed"] = "Bestie füttern\n|cffffffffMit diesem Kommando kann man die Bestie füttern.|r\n\n|cffff0000Linksklicken um die Bestie zu füttern|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.beast.call"] = "Bestie herbeirufen\n|cffffffffMit diesem Kommando kann man die Bestie herbeirufen.|r\n\n|cffff0000Linksklicken um die Bestie herbeizurufen|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.creator.master"] = "Ersteller-Kontrolle\n|cffffffffMit dieser Kontrolle kannst du Bots nach Klasse erstellen.\nDie Standardgrenze beträgt 40 Bots pro Account.\nEs gibt keinen Befehl, um sie nach der Erstellung zu löschen.\nFüge sie deshalb deiner Freundesliste hinzu, um sie wiederverwenden zu können.\nDie Ausführungsreihenfolge zeigt, wer die Befehle erhält.|r\n\n|cffff0000Linksklick zum Ein-/Ausblenden der Optionen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.warrior"] = "Krieger-Erstellen\n|cffffffffDieser Button erstellt einen Krieger-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Kriegers zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.warlock"] = "Hexenmeister-Erstellen\n|cffffffffDieser Button erstellt einen Hexenmeister-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Hexenmeisters zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.shaman"] = "Schamane-Erstellen\n|cffffffffDieser Button erstellt einen Schamanen-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Schamanen zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.rogue"] = "Schurke-Erstellen\n|cffffffffDieser Button erstellt einen Schurken-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Schurken zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.priest"] = "Priester-Erstellen\n|cffffffffDieser Button erstellt einen Priester-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Priesters zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.paladin"] = "Paladin-Erstellen\n|cffffffffDieser Button erstellt einen Paladin-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Paladins zu wählen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.mage"] = "Magier-Erstellen\n|cffffffffDieser Button erstellt einen Magier-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Magiers zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.hunter"] = "Jäger-Erstellen\n|cffffffffDieser Button erstellt einen Jäger-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Jägers zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.druid"] = "Druide-Erstellen\n|cffffffffDieser Button erstellt einen Druiden-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Druiden zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.deathknight"] = "Todesritter-Erstellen\n|cffffffffDieser Button erstellt einen Todesritter-Bot.|r\n\n|cffff0000Linksklick, um das Geschlecht deines Todesritters zu wählen.|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.notarget"] = "Ich habe kein Ziel.",
  ["tips.creator.gendermale"] = "Erstellt einen männlichen Begleiter.\n|cffffffffStark, mutig und immer bereit für den Kampf... oder ein Bier.|r\n\n|cffff0000Linksklick zum Erstellen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.genderfemale"] = "Erstellt eine weibliche Begleiterin.\n|cffffffffAnmutig, tödlich und niemals zu unterschätzen.|r\n\n|cffff0000Linksklick zum Erstellen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.genderrandom"] = "Erstellt einen Bot mit zufälligem Geschlecht.\n|cffffffffDas Schicksal wird entscheiden!|r\n\n|cffff0000Linksklick zum Erstellen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.creator.inspect"] = "Ziel betrachten\n|cffffffffDiese Schaltfläche öffnet ein Dialog-Fenster in dem man sein Ziel betrachten kann.|r\n\n|cffff0000Linksklicken um das Ziel zu betrachten|r\n|cff999999(Ausführreihenfolge: Ziel)|r",
  ["tips.creator.init"] = "Auto-Initialisiern\n|cffffffffDiese Schaltfläche initialisiert ein(e) Ziel, Raid oder Party automatisch.\nEs gibt 2 Limitationen, damit keine Ausrüstung überschrieben wird:\n- es funktioniert nicht mit Bots auf dem Playerbot-Roster.\n- es funktioniert nicht mit Bots auf dem Gilden-Roster.|r\n\n|cffff0000Linksklicken um ein Ziel zu initialisieren|r\n|cff999999(Ausführreihenfolge: Ziel)|r\n\n|cffff0000Rechtsklicken um eine Gruppe zu initialisieren|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.unit.selfbot"] = "Selfbot\n|cffffffffDiese Schaltfläche schaltet den Selfbot-Modus ein und aus.|r\n\n|cffff0000Linksklicken um Selfbot ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.unit.button"] = "|cffffffff\nMit dieser Schaltfläche kann man NAME in seine Gruppe ein- oder ausladen.\nMultiBot wird den Playerbot nach seinen Kampf- und Nicht-Kampf-Strategien fragen.\nDie Strategien können mit der linken und rechten Schaltflächenleiste konfiguriert werden.\nDie Schaltflächenleisten erscheinen nach dem einalden eines Bots.|r\n\n|cffff0000Linksklicken um NAME einzuladen|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um NAME auszuladen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.master"] = "Unit-Control\n|cffffffffIn dieser Steuereinheit findet man die Playerbots.\nJede Schaltfläche steht für einen Character, Gilden-Mitglied oder Freund.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Einheiten ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um die Roster zu aktualisieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.filter"] = "Klassen-Filter\n|cffffffffMit dem Klassen-Filter kann man die Einheiten nach ihrer Klasse filtern.|r\n\n|cffff0000Linksklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um den Filter zu entfernen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.deathknight"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Todesrittern.|r\n\n|cffff0000Linksklicken um nach Todesrittern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.druid"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Druiden.|r\n\n|cffff0000Linksklicken um nach Druiden zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.hunter"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Jägern.|r\n\n|cffff0000Linksklicken um nach Jägern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.mage"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Magiern.|r\n\n|cffff0000Linksklicken um nach Magiern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.paladin"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Paladine.|r\n\n|cffff0000Linksklicken um nach Paladine zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.priest"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Priestern.|r\n\n|cffff0000Linksklicken um nach Priestern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.rogue"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Schurken.|r\n\n|cffff0000Linksklicken um nach Schurken zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.shaman"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Schamanen.|r\n\n|cffff0000Linksklicken um nach Schamanen zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.warlock"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Hexenmeistern.|r\n\n|cffff0000Linksklicken um nach Hexenmeistern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.warrior"] = "Klassen-Filter\n|cffffffffFiltert die Einheiten nach Kriegern.|r\n\n|cffff0000Linksklicken um nach Kriegern zu filtern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.none"] = "Klassen-Filter\n|cffffffffEntfernt den Klassen-Filter von den Einheiten.|r\n\n|cffff0000Linksklicken um den Filter zu entfernen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.roster"] = "Roster-Filter\n|cffffffffMit dem Roster-Filter kann man zwischen den verschienden Rostern wechseln.|r\n\n|cffff0000Linksklicken um die Optionen ein- und auszublenden|r\n|cffff0000Rechtsklick, um zum aktiven Dienstplan zu wechseln|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.actives"] = "Roster-Filter\n|cffffffffZeigt alle aktiven Gruppen-Mitglieder an.|r\n\n|cffff0000Linksklicken um den Aktiv-Roster auszuwählen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.players"] = "Roster-Filter\n|cffffffffZeigt den Playerbot-Roster.\nNormalerweise deine Characteren und Andere welche in der Gruppe verblieben sind.|r\n\n|cffff0000Linksklicken um den Playerbot-Roster auszuwählen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.members"] = "Roster-Filter\n|cffffffffZeigt den Gilden-Roster.\nDer Gilden-Roster zeigt nicht deine eigenen Character an.|r\n\n|cffff0000Linksklicken um den Gilden-Roster auszuwählen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.friends"] = "Roster-Filter\n|cffffffffZeigt den Freunde-Roster.\nDer Freund-Roster zeigt nicht deine eignen Character und nicht die Gilden-Mitglieder an.|r\n\n|cffff0000Linksklicken um den Freunde-Roster auszuwählen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.favorites"] = "Roster-Filter\n|cffffffffNur die Bots anzeigen, die du als Favoriten markiert hast.|r\n\n|cffff0000Linksklick zum Aktivieren|r\n|cff999999(Ausgeführt von: System)|r",
  ["tips.units.pvpstatsmaster"] = "PvP-Statistiken\n|cffffffffSende PvP-Statistik-Befehl an...|r\n\n|cffff0000Linksklick, um das Menü zu öffnen|r\n|cff999999(Ausgeführt von: System)|r",
  ["tips.units.pvpstatstobot"] = "An Bot senden",
  ["tips.units.pvpstatstoparty"] = "An Gruppe senden",
  ["tips.units.pvpstatstoraid"] = "An Schlachtzug senden",
  ["tips.units.browse"] = "Browse\n|cffffffffMit dieser Schaltfläche kann man den Roster durchblättern.\nSie wird ausgeblendet sobald ein Roster weniger als 11 Einheiten hat.|r\n\n|cffff0000Linksklicken um den Roster durchzublättern|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.invite"] = "Invite-Control\n|cffffffffMit dieser Steuereinheit kann man die Gruppe automatisch auffüllen.\nDie linke Schaltfläche ist für 'Party-Invite', die rechten Schaltflächen sind für 'Raid-Invite'.\nEin Rechtsklick auf diese Schaltfläche addiert oder entfernt alle Bots auf einmal.\nSeid ihr in keiner Gruppe, werden alle Bots hinzugefügt, andernfalls entfernt.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um alle Bots hinzuzufügen oder zu entfernen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.inviteParty5"] = "5er Party\n|cffffffffMit dieser Schaltfläche füllt man seine Party auf.\nDiese Funktion nimmt Einheiten vom aktuellen Roster und ignoriert dabei den Klassen-Filter.\nSie hält am Ende des Rosters oder sobald die Gruppe 5 Mitglieder hat.|r\n\n|cffff0000Linksklicken um Party-Mitglieder einzuladen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.inviteRaid10"] = "10er Raid\n|cffffffffMit dieser Schaltfläche füllt man sein Raid auf.\nDiese Funktion nimmt Einheiten vom aktuellen Roster und ignoriert dabei den Klassen-Filter.\nSie hält am Ende des Rosters oder sobald die Gruppe 10 Mitglieder hat.|r\n\n|cffff0000Linksklicken um Raid-Mitglieder einzuladen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.inviteRaid25"] = "25er Raid\n|cffffffffMit dieser Schaltfläche füllt man sein Raid auf.\nDiese Funktion nimmt Einheiten vom aktuellen Roster und ignoriert dabei den Klassen-Filter.\nSie hält am Ende des Rosters oder sobald die Gruppe 25 Mitglieder hat.|r\n\n|cffff0000Linksklicken um Raid-Mitglieder einzuladen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.inviteRaid40"] = "40er Raid\n|cffffffffMit dieser Schaltfläche füllt man sein Raid auf.\nDiese Funktion nimmt Einheiten vom aktuellen Roster und ignoriert dabei den Klassen-Filter.\nSie hält am Ende des Rosters oder sobald die Gruppe 40 Mitglieder hat.|r\n\n|cffff0000Linksklicken um Raid-Mitglieder einzuladen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.units.alliance"] = "Alle PlayerBots ein-/ausloggen\n|cffffffffLoggt alle PlayerBots ein oder aus, auf die du Zugriff hast.\nDiese Funktion kann je nach Gesamtanzahl der PlayerBots einige Zeit benötigen,\num die Buttonleisten für jeden PlayerBot zu laden.\n\n|cffff0000Linksklick, um alle PlayerBots einzuloggen|r\n|cff999999(Ausgeführt von: System)|r\n\n|cffff0000Rechtsklick, um alle PlayerBots auszuloggen|r\n|cff999999(Ausgeführt von: System)|r",
  ["options.minimap.explainer"] = "Blendet den MultiBot-Minimap-Button ein oder aus.",
