  ["tips.sliders.rstbutn"] = "Zurücksetzen",
  ["tips.main.master"] = "Main-Control\n|cffffffffIn dieser Steuereinheit findet man die Auto-Schalter und Reset-Kommandos.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken und halten um MultiBar zu verschieben|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.options"] = "Optionen-Schalter\n|cffffffffÖffnet das MultiBot-Einstellungsfenster mit Schiebereglern für Aktionsintervalle.\n(Statistiken / Talente / Einladung / Sortieren) und Chat-Drosselung (Nachrichten pro Sekunde / Burst).\nEinstellungen werden pro Charakter gespeichert.|r\n\n|cffff0000Linksklick zum Öffnen oder Schließen des Optionsfensters|r\n|cff999999(Ausführungsreihenfolge: Interface)|r",
  ["tips.main.coords"] = "Reset-Coords\n|cffffffffSetzt die Koordinaten der folgenden Erweiterungen zurück:\nMultiBar, Inventar, Zauberbuch, Itemus, Iconos und Reward-Selector|r\n\n|cffff0000Linksklicken um die Koordinaten zurückzusetzen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.masters"] = "GameMaster-Switch\n|cffffffffDieser Schalter aktiviert oder deaktiviert die GameMaster-Control.\nMan benötigt GameMaster-Rechte um die GameMaster-Control zu aktivieren.|r\n\n|cffff0000Linksklicken um die GameMaster-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.rtsc"] = "RTSC-Switch\n|cffffffffDieser Schalter aktiviert oder deaktiviert die RTSC-Control.|r\n\n|cffff0000Linksklicken um die RTSC-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.raidus"] = "Raidus-Switch\n|cffffffffDieser Schalter öffnet oder schließt den Raid-Composer.|r\n\n|cffff0000Linksklicken um die Raid-Composer zu öffnen oder zu schließen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.creator"] = "Creator-Switch\n|cffffffffDieser Schalter aktiviert oder deaktiviert die Creator-Control.|r\n\n|cffff0000Linksklicken um die Creator-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.beast"] = "Beastmaster-Switch\n|cffffffffDieser Schalter aktiviert oder deaktiviert die Beastmaster-Control.\nDie Beastmaster-Control ist für Mod-NPC-Beastmaster des Azerothcore.\nMod-NPC-Beastmaster erlaubt es jedem Character eine Bestie wie Jäger zu haben.\nDein Character kann die notwendigen Zauber bei 'White Fang' erlernen.\nDer GameMaster muss 'White Fang' in der Spielwelt platzieren.\n|cffff0000Linksklicken um die Beastmaster-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.disperse"] = "Disperse-Switch\n|cffffffffDieser Schalter zeigt oder versteckt die Disperse-Control.|r\n\n|cffff0000Linksklicken um die Disperse-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.loot"] = "Beuteregeln-Switch\n|cffffffffDieser Schalter zeigt oder versteckt die Beuteregeln-Control.|r\n\n|cffff0000Linksklicken um die Beuteregeln-Control ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.expand"] = "Expand-Switch\n|cffffffffDiese Schaltfläche expandiert oder reduziert die Stay-Follow-Control.\n|cffff0000Linksklicken um die Stay-Follow-Control zu expandieren oder reduzieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.release"] = "Auto-Release\n|cffffffffDiese Erweiterung erkennt wenn ein Bot stirbt.\nTote Bots werden automatisch freigelassen und herbeigerufen.\nDadurch werden die Bots innerhalb von Sekunden wiederbelebt.|r\n\n|cffff0000Linksklicken um Auto-Release ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.stats"] = "Auto-Stats\n|cffffffffDiese Erweiterung visualisiert die Werte vom Stats-Kommando.\nDie Stats-Werte aktualisieren sich alle 45 Sekunden.|r\n\n|cffff0000Linksklicken um Auto-Stats ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.reward"] = "Reward-Selector\n|cffffffffDiese Erweiterung visualisiert die Auswahl von Belohnungen.\nMein Rat ist, zuerest die Belohnung für den eigenen Character auszuwählen.\nDann hat man keine Probleme beim Betrachten der Bots.|r\n\nWichtig:\nSobald der eigene Character eine Quest beendet hat, müssen auch alle Bots die Quest beenden.\nAlso brecht nicht den Reward-Selector ab sobald der eigene Character seine Belohnung hat.\n\n|cffffffffMod-Playerbot-Konfiguration:\n- (muss) AiPlayerbot.AutoPickReward = no\n- (sollte) AiPlayerbot.SyncQuestWithPlayer = 1|r\n\n|cffff0000Linksklicken um Reward-Selector ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um Reward-Selector zu öffnen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.main.reset"] = "Reset-Bots\n|cffffffffDiese Schaltfläche setzt die künstliche Intelligenz der Bots zurück.|r\n\n|cffff0000Linksklicken um die künstliche Intelligenz zurückzusetzen|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.main.action"] = "Reset-Action\n|cffffffffDiese Schaltfläche bricht die aktuelle Aktion der Bots ab.|r\n\n|cffff0000Linksklicken um die Aktion abzubrechen|r\n|cff999999(Ausführreihenfolge: Ziel, Raid, Party)|r",
  ["tips.game.master"] = "GameMaster-Control\n|cffffffffIn dieser Steuereinheit findet man nützliche GameMaster-Kommandos und -Werkzeuge.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um MultiBot zu schließen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.game.necronet"] = "Necro-Network\n|cffffffffDiese Schaltfläche aktiviert oder deaktiviert das Necro-Network.\nWenn das Necro-Network aktiviert ist, findet man Grabstein-Schaltflächen auf der Weltkarte.\nMit jeder Grabstein-Schaltfläche kann man sich zum entsprehenden Friedhof teleportieren.\nMan benötigt GameMaster-Rechte um diese Schaltflächen zu benutzen.|r\n\n|cffff0000Linksklicken um Necro-Network ein- oder auszuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.game.portal"] = "Memory-Portal\n|cffffffffIn dieser Kiste findet man die Memory-Steine.\nBenutze die Memory-Steine um deine aktuelle Position zu speichern.\nMit einen Memory-Stein kann man sich jederzeit an die gespeicherte Position teleportieren.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.game.memory"] = "Memory-Gem\n|cffffffffDieser Memory-Stein ABOUT.\nMan benötigt GameMaster-Rechte um diese Schaltflächen zu benutzen.|r\n\n|cffff0000Linksklicken um eine Position zu speichern oder abzurufen|r\n|cff999999(Ausführreihenfolge: Selbst)|r\n\n|cffff0000Rechtsklicken um eine Position zu vergessen|r\n|cff999999(Ausführreihenfolge: Selbst)|r",
  ["tips.game.itemus"] = "Itemus\n|cffffffffMan findet jedes Item in der Kiste des GameMasters.\nZiehlt auf einen Spieler oder Bot, mit einem Linksklick auf das Item werden Träume war.\nWichtig, nicht jedes Item kann man generieren, daher muss man es schon ausprobieren.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Itemus zu öffnen oder schließen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.game.iconos"] = "Iconos\n|cffffffffMan findet jedes Icon inklusive Pfadangabe in diesem Werkzeug.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Iconos zu öffnen oder schließen|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.game.summon"] = "Summon\n|cffffffffBeschwört einen anvisierten Spieler oder Bot an deine Position.\nMan benötigt GameMaster-Rechte um diese Schaltflächen zu benutzen.|r\n\n|cffff0000Linskklicken um das Ziel zu beschwören|r\n|cff999999(Ausführreihenfolge: Ziel)|r",
  ["tips.game.appear"] = "Appear\n|cffffffffDu erscheinst an der Position des anvisierten Spielers oder Bots.\nMan benötigt GameMaster-Rechte um diese Schaltflächen zu benutzen.|r\n\n|cffff0000Linksklicken um beim Ziel zu erscheinen|r\n|cff999999(Ausführreihenfolge: Ziel)|r",
  ["tips.game.delsvwarning"] = "|cffff4444WARNUNG|r: Sie sind dabei, ALLE gespeicherten Variablen von MultiBot zu löschen.\nDiese Aktion ist unwiderruflich.\n\nMöchten Sie fortfahren?",
  ["tips.game.delsv"] = "Gespeicherte Variablen löschen\n|cffffffffMit diesem Button werden alle Daten in der Datei MultiBot SavedVariables (MultiBot.lua) dauerhaft gelöscht.\nDiese Aktion kann nicht rückgängig gemacht werden. Bitte vorsichtig verwenden!|r\n\n|cffff0000Linksklick zum Löschen|r\n|cff999999(Auf Systemebene ausgeführt)|r",
  ["tips.quests.master"] = "Quest-Steuerung\n|cffffffffDiese Steuerung zeigt die aktuelle Liste der Quests an.\nLinksklick auf die Seiten, um die Quest mit deinen Bots zu teilen.\nRechtsklick auf die Seiten, um deine und die Quests deiner Bots aufzugeben.\nDie Ausführungsreihenfolge zeigt den Empfänger der Befehle.|r\n\n|cffff0000Linksklick, um die Optionen ein-/auszublenden|r\n|cff999999(Ausführungsreihenfolge: System)|r\n\n|cffff0000Rechtsklick, um die Optionen zu aktualisieren|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.quests.accept"] = "Quest-Annehmen\n|cffffffffDieser Button befiehlt den Bots, alle Quests vom anvisierten NPC anzunehmen.\n\n|cffff0000Linksklick, um alle Quests anzunehmen|r\n|cff999999(Ausführungsreihenfolge: Schlachtzug, Gruppe)|r",
  ["tips.quests.main"] = "Questmenü öffnen\n|cffffffffDieser Button öffnet das Questmenü.\n\n|cffff0000Linksklick zum Öffnen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.quests.talk"] = "Mit NPC sprechen\n|cffffffffDieser Button befiehlt den Bots, mit dem ausgewählten NPC zu sprechen, um eine Quest anzunehmen oder abzugeben.\n\n|cffff0000Linksklick zum Ausführen|r\n|cff999999(Ausführungsreihenfolge: Schlachtzug, Gruppe)|r",
  ["tips.quests.talkerror"] = "Bitte wähle einen NPC zum Sprechen aus.",
  ["tips.quests.questcomperror"] = "Bitte wähle einen Bot aus, um seine Quests abzufragen.",
  ["tips.quests.sendwhisp"] = "Bot fragen",
  ["tips.quests.sendpartyraid"] = "Gruppe oder Schlachtzug fragen.",
  ["tips.quests.completed"] = "Abgeschlossene Quests\n|cffffffffMit diesem Button kannst du einen Bot oder alle Bots nach der Liste der abgeschlossenen Quests fragen.\n\n|cffff0000Linksklick, um das Untermenü zu öffnen|r\n|cff999999(Ausführungsreihenfolge: Schlachtzug, Gruppe, Bot)|r",
  ["tips.quests.incompleted"] = "Unvollständige Quests\n|cffffffffMit diesem Button kannst du einen Bot oder alle Bots nach der Liste der unvollständigen Quests fragen.\n\n|cffff0000Linksklick, um das Untermenü zu öffnen|r\n|cff999999(Ausführungsreihenfolge: Schlachtzug, Gruppe, Bot)|r",
  ["tips.quests.allcompleted"] = "Alle Quests\n|cffffffffMit diesem Button kannst du einen Bot oder alle Bots nach der Liste aller Quests fragen.\n\n|cffff0000Linksklick, um das Untermenü zu öffnen|r\n|cff999999(Ausführungsreihenfolge: Schlachtzug, Gruppe, Bot)|r",
  ["tips.quests.incomplist"] = "Aktuelle Quests vom Bot(s)",
  ["tips.quests.complist"] = "Liste der abgeschlossenen Quests des/der Bot(s)",
  ["tips.quests.alllist"] = "Alle Quests des/der Bot(s)",
  ["tips.quests.compheader"] = "** Abgeschlossene Quests **",
  ["tips.quests.incompheader"] = "** Unvollständige Quests **",
  ["tips.quests.drop"] = "Aufgeben",
  ["tips.quests.botsword"] = "Bots : ",
  ["tips.quests.gobsmaster"] = "GameObjects-Menü öffnen\n|cffffffffDieser Button öffnet das GameObjects-Menü.|r\n\n|cffff0000Linksklick zum Öffnen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.quests.gobenter"] = "GameObject benutzen\n|cffffffffDieser Button öffnet ein Feld zur Eingabe des GameObject-Namens.\n\n|cffff0000Linksklick zum Öffnen des Eingabefeldes|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.quests.gobsearch"] = "Nach GameObject suchen\n|cffffffffDieser Button öffnet ein Fenster, das die nutzbaren GameObjects der Bots anzeigt.\n\n|cffff0000Linksklick zum Öffnen des Fensters|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.quests.goberrorname"] = "Bitte einen gültigen GameObject-Namen eingeben.",
  ["tips.quests.gobselectboterror"] = "Bitte wähle einen Bot aus, dem du den Befehl senden möchtest.",
  ["tips.quests.gobsnameerror"] = "Bitte einen Namen eingeben.",
  ["tips.quests.gobctrlctocopy"] = "STRG + C zum Kopieren",
  ["tips.quests.gobselectall"] = "Alle auswählen",
  ["tips.quests.gobsfound"] = "Gefundene GameObjects",
  ["tips.quests.gobpromptname"] = "GameObject Name",
  ["tips.quests.gobnosearchdata"] = "No search data captured.",
  ["tips.group.group"] = "Gruppenaktionen-Auswahl\n|cffffffffÖffnet ein Untermenü mit den folgenden Gruppenaktionen:\nTrinken, Freilassen, Wiederbeleben.|r\n\n|cffff0000Linksklick zum Erweitern.|r",
  ["tips.drink.group"] = "Group-Drink\n|cffffffffMit diesem Kommando befiehlt man der Gruppe etwas zu trinken.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Group-Drink auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.release.group"] = "Group-Release\n|cffffffffMit diesem Kommando geben die toten Bots ihre Geister auf den nächsten Friedhof frei.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Group-Release auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.revive.group"] = "Group-Revive\n|cffffffffMit diesem Kommando werden Geister-Bots auf dem nächsten Friedhof wiederbelebt.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Group-Revive auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.summon.group"] = "Group-Summon\n|cffffffffMit diesem Kommando ruft man die Gruppe an seine Position.\nDie Ausführreihenfolge zeigt die Empfänger des Befehls.|r\n\n|cffff0000Linksklicken um Group-Summon auszuführen|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r",
  ["tips.allbots.sellallvendor"] = "Alle verkaufbaren grauen Gegenstände verkaufen (ALLE BOTS)|cffffffff\nAlle deine Bots (die im Einheitenfenster aufgeführt sind) werden alle Gegenstände verkaufen,\ndie sicher an den aktuell anvisierten Händler verkauft werden können.\nGeschützte Gegenstände (Schlüssel, Ruhestein usw.) werden niemals verkauft.|r\n\n|cffff0000Betroffen sind alle Bots, die im Einheitenfenster aufgeführt sind.|r\n|cff999999(Ausgeführt von: jedem Bot)|r",
  ["tips.allbots.commandsallbots"] = "Ermöglicht dir, Befehle an alle Bots zu senden|cffffffff\nAlle deine Bots (die im Einheitenfenster aufgeführt sind) werden den Befehl ausführen\n\n|cffff0000Betroffen sind alle Bots, die im Einheitenfenster aufgeführt sind.|r\n|cff999999(Ausgeführt von: jedem Bot)|r",
  ["tips.allbots.maintenanceallbots"] = "Wartung (ALLE BOTS)|cffffffff\nAlle deine Bots (die im Einheitenfenster aufgeführt sind) werden den 'maintenance'-Befehl ausführen.\nNutze dies, wenn du möchtest, dass jeder Bot seine vollständige Wartungsroutine gleichzeitig durchführt.|r\n\n|cffff0000Betroffen sind alle Bots, die im Einheitenfenster aufgeführt sind.|r\n|cff999999(Ausgeführt von: jedem Bot)|r",
  ["tips.inventory.sell"] = "Items verkaufen|cffffffff\nDiese Schaltfläche aktiviert den Verkaufs-Modus des Inventars.\nMan muss einen Händler als Ziel ausgewählt haben.\nAus Sicherheitsgründen verkaufen Bots keine:\n- Items mit 'Schlüssel' in ihrem Namen\n- Items wie den Ruhestein|r\n\n|cffff0000Linksklicken um Verkauf zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.inventory.sellgrey"] = "Alles Graue verkaufen|cffffffff\nDer Bot verkauft alle Gegenstände von minderwertiger Qualität (grau) beim ausgewählten Händler.\nStelle sicher, dass du einen Händler ausgewählt hast und der Bot in Reichweite ist.|r\n\n|cffff0000Betrifft nur den Bot, dessen Inventar geöffnet ist.|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.inventory.sellvendor"] = "Alles verkaufen, was verkaufbar ist|cffffffff\nDer Bot verkauft alle verkaufbaren Gegenstände bei diesem Händler.\nGeschützte Gegenstände (Schlüssel, Ruhestein usw.) werden niemals verkauft.|r\n\n|cffff0000Betrifft nur den Bot, dessen Inventar geöffnet ist.|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.inventory.equip"] = "Items ausrüsten|cffffffff\nDiese Schaltfläche aktiviert den Ausrüst-Modus des Inventars.|r\n\n|cffff0000Linksklicken um Ausrüsten zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.inventory.use"] = "Items benutzen|cffffffff\nDiese Schaltfläche aktiviert den Benutzen-Modus des Inventars.|r\n\n|cffff0000Linksklicken um Benutzen zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.inventory.trade"] = "Items tauschen|cffffffff\nDiese Schaltfläche aktiviert den Tausch-Modus des Inventars.\nDen Inspekt-Frame muss man manuell schließen.\nEs gibt kein LUA-Befehl dafür.|r\n\n|cffff0000Linksklicken um Tasuchen zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.inventory.drop"] = "Items zerstören|cffffffff\nDiese Schaltfläche aktiviert den Zerstör-Modus des Inventars.\nAus Sicherheitsgründen zerstören Bots keine:\n- Items mit einer Qualität von Episch oder besser\n- Items mit 'Schlüssel' in ihrem Namen\n- den Ruhestein|r\n\n|cffff0000Linktsklicken um Zerstören zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.inventory.open"] = "Items öffnen|cffffffff\nDiese Schaltfläche öffnet die erste auffindbare Beute-Tasche im Inventar.\nDer Inhalt wird automatisch in das Inventar gelegt.|r\n\n|cffff0000Linksklicken um eine Beute-Tasche zu öffnen|r\n|cff999999(Ausführreihenfolge-Order: Bot)|r",
  ["tips.itemus.level.master"] = "Level-Filter|cffffffff\nFiltert die Items nach Level in 10er Schritten.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L10"] = "Level 0 bis 10|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 0 bis 10 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L20"] = "Level 11 bis 20|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 11 bis 20 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L30"] = "Level 21 bis 30|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 21 bis 30 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L40"] = "Level 31 bis 40|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 31 bis 40 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L50"] = "Level 41 bis 50|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 41 bis 50 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L60"] = "Level 51 bis 60|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 51 bis 60 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L70"] = "Level 61 bis 70|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 61 bis 70 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.level.L80"] = "Level 71 bis 80|cffffffff\nZeigt alle Items mit einer Level-Vorraussetzung von 71 bis 80 an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.master"] = "Quality-Filter|cffffffff\nFiltert die Items nach Qualität.\nDieser Filter ist additiv zum Level-Filter.|r\n\n|cffff0000Linksklicken um die Optionen ein- und auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R00"] = "Poor-Quality|cffffffff\nZeigt alle Items von schlechter Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R01"] = "Common-Quality|cffffffff\nZeigt alle Items von einfacher Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R02"] = "Non-Common-Quality|cffffffff\nZeigt alle Items von unüblicher Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R03"] = "Rare-Quality|cffffffff\nZeigt alle Items von seltener Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R04"] = "Epic-Quality|cffffffff\nZeigt alle Items von epischer Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R05"] = "Legendary-Quality|cffffffff\nZeigt alle Items von legendärer Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R06"] = "Artifact-Quality|cffffffff\nZeigt alle Items der Artefakt-Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.rare.R07"] = "Heirlooms-Quality|cffffffff\nZeigt alle Items der Erbstück-Qualität an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.master"] = "Slot-Filter|cffffffff\nFiltert die Items nach Ausrüstungsplätzen.\nDieser Filter ist additiv zum Level- und Qualitäts-Filter.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S00"] = "Non-Equipable|cffffffff\nZeigt alle nicht ausrüstbaren Items an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S01"] = "Head-Slot|cffffffff\nZeigt alle Items die man am Kopf ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S02"] = "Neck-Slot|cffffffff\nZeigt alle Items die man am Hals ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S03"] = "Shoulder-Slot|cffffffff\nZeigt alle Items die man an den Schultern ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S04"] = "Shirt-Slot|cffffffff\nZeigt alle Items die man als Hemd ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S05"] = "Chest-Slot|cffffffff\nZeigt alle Items die man an der Brust ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S06"] = "Waist-Slot|cffffffff\nZeit alle Items die man an der Taille ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S07"] = "Legs-Slot|cffffffff\nZeigt alle Items die man an den Beinen ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S08"] = "Feets-Slot|cffffffff\nZeigt alle Items die man an den Füßen ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S09"] = "Wrists-Slot|cffffffff\nZeigt alle Items die man am Handgelenken ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S10"] = "Hands-Slot|cffffffff\nZeigt alle Items die man an den Händen ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S11"] = "Finger-Slot|cffffffff\nZeigt alle Items die man an dem Fingern ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S12"] = "Trinket-Slot|cffffffff\nZeigt alle Items die man an den Ohren ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S13"] = "One-Hand-Weapon-Slot|cffffffff\nZeigt alle Items die man als Einhandwaffe ausrüsten kann an.\nDiese Waffen können in der Haupt- und Nebenhand geführt werden.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S14"] = "Shield-Slot|cffffffff\nZeigt alle Items die man als Schild ausrüsten kann an.\nSchilde werden immer in der Nebenhand geführt.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S15"] = "Ranged-Slot|cffffffff\nZeigt alle Items die man als Fernkampfwaffe ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S16"] = "Back-Slot|cffffffff\nZeigt alle Items die man am Rücken ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S17"] = "Two-Hand-Weapon-Slot|cffffffff\nZeigt alle Items die man als Zweihandwaffe ausrüsten kann an.\nDiese Waffen werden in der Haupthand geführt und blockieren die Nebenhand.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S18"] = "Bag-Slot|cffffffff\nZeigt alle Items die man als Tasche ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S19"] = "Tabard-Slot|cffffffff\nZeigt alle Items die als Wappenrock ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S20"] = "Robe-Slot|cffffffff\nZeigt alle Items die man als Robe ausrüsten kann an.\nRoben werden an der Burst ausgerüstet.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S21"] = "Main-Hand-Weapons-Slot|cffffffff\nZeigt alle Waffen die man in der Haupthand ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S22"] = "Off-Hand-Weapons-Slot|cffffffff\nZeigt alle Waffen die man in der Nebenhand ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S23"] = "Off-Hand-Items-Slot|cffffffff\nZeigt alle Items die man in der Nebenhand ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S24"] = "Ammo-Slot|cffffffff\nZeigt alle Items die man als Munition ausrüsten kann an.\nDieser Rüstplatz ist der gleiche wie 'Ranged-Right'|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S25"] = "Throw-Slot|cffffffff\nZeigt alle Items die man als Wurfwaffen ausrüsten kann an.\nDieser Rüstplatz ist der gleiche wie 'Ranged'|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S26"] = "Ranged-Right-Slot|cffffffff\nZeigt alle Items die man als Munition ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S27"] = "Quiver-Slot|cffffffff\nZeigt alle Items die man als Köcher ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.slot.S28"] = "Relic-Slot|cffffffff\nZeigt alle Items die man als Relikt ausrüsten kann an.|r\n\n|cffff0000Linksklicken um diesen Filter zu aktivieren|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.itemus.type"] = "Type-Filter|cffffffff\nMit diesem Filter kann man zwischen Player-Character und Non-Player-Character Items wechseln.\nDieser Filter ist additiv zum Level-, Qualitäts- und Slot-Filter.|r\n\n|cffff0000Linksklicken zwischen PC- und NPC-Ausrüstung umzuschalten|r\n|cff999999(Ausführreihenfolge: System)|r",
  ["tips.deathknight.playbook.master"] = "Präsenz-Control|cffffffff\nDiese Steuereinheit erlaubt es die Präsenz auszuwählen, zu aktivieren oder deaktivieren.|r\n\n|cffff0000Linksklicken um die Optionen ein- oder auszublenden|r\n|cff999999(Ausführreihenfolge: System)|r\n\n|cffff0000Rechtsklicken um die Präsenz ein- oder auszuschalten.|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.deathknight.playbook.unholy"] = "Unheilige-Präsenz|cffffffff\nDiese Option aktiviert die Unheilige-Präsenz.|r\n\n|cffff0000Linksklicken um die Unheilige-Präsenz zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.deathknight.playbook.frost"] = "Eisige-Präsenz|cffffffff\nDiese Option aktiviert die Eisige-Präsenz.|r\n\n|cffff0000Linksklicken um die Eisige-Präsenz zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.deathknight.playbook.blood"] = "Blutige-Präsenz|cffffffff\nDiese Option aktiviert die Blutige-Präsenz.|r\n\n|cffff0000Linksklicken um die Blutige-Präsenz zu aktivieren|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.deathknight.strategy.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.deathknight.strategy.frostAoe"] = "FROST-AOE|cffffffff\nAktiviert die Frost-AOE-Strategie.\nFrost-AOE und Unheilig-AOE schließen sich gegenseitig aus.\nNur eine dieser Strategien kann aktiv sein.|r\n\n|cffff0000Linksklick zum Aktivieren/Deaktivieren von Frost-AOE|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.deathknight.strategy.unholyAoe"] = "UNHEILIG-AOE|cffffffff\nAktiviert die Unheilig-AOE-Strategie.\nFrost-AOE und Unheilig-AOE schließen sich gegenseitig aus.\nNur eine dieser Strategien kann aktiv sein.|r\n\n|cffff0000Linksklick zum Aktivieren/Deaktivieren von Unheilig-AOE|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.druid.playbook.master"] = "Playbook|cffffffff\nIm Playbook findet man die Klassen-typischen Strategien.|r\n\n|cffff0000Linksklicken um das Playbook ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: System)|r",
  ["tips.druid.playbook.caster"] = "Caster|cffffffff\nDiese Strategie macht den Druiden zum Zauberer.\nBär, Katze, Zauberer und Heiler schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Caster ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.druid.playbook.cat"] = "Cat|cffffffff\nDiese Strategie versetzt den Druiden in die Katzen-Gestalt.\nBär, Katze, Zauberer und Heiler schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Cat ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.druid.playbook.bear"] = "Bear|cffffffff\nDiese Strategie versetzt den Druiden in die Bären-Gestalt.\nBär, Katze, Zauberer und Heiler schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Bear ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.druid.playbook.resto"] = "Resto|cffffffff\nWiederherstellungs-Druide, fokussiert auf Heilung.\nBär, Katze, Gleichgewicht und Wiederherstellung schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Resto ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.druid.strategy.blanketing"] = "",
  ["tips.druid.strategy.tranquility"] = "",
  ["tips.druid.strategy.feralCharge"] = "",
  ["tips.druid.strategy.healerdps"] = "Heiler-DPS|cffffffff\nAktiviert die hybride Heiler-DPS-Strategie.\nVerursacht standardmäßig Schaden und heilt bei Bedarf.\nSchließt Heilen und OffHeal aus.|r\n\n|cffff0000Linksklick, um Heiler-DPS ein/auszuschalten|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.druid.strategy.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.druid.strategy.offheal"] = "OffHeal|cffffffff\nDeaktiviert den DPS-Modus und aktiviert OffHeal,\nDie Bots konzentrieren sich auf Schaden, heilen aber bei Bedarf.\nNur für Wildheits-Druiden.|r\n\n|cffff0000Linksklick, um OffHeal zu aktivieren oder zu deaktivieren|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.pet.master"] = "Tierbefehle|cffffffff\nÖffnet eine Leiste mit mehreren Optionen zum Herbeirufen von Begleitern.|r\n\n|cffff0000Linksklick, um Optionen anzuzeigen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.hunter.pet.name"] = "Rufe ein Tier nach |cff00ff00seinem Namen|r\n|cffffffffÖffnet eine Liste verfügbarer Begleiter – klicke auf einen Namen, um ihn zu rufen.|r\n\n|cffff0000Linksklick, um die Liste zu öffnen|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.pet.id"] = "Rufe ein Tier nach |cff00ff00DB-ID|r\n|cffffffffNutze die Datenbank-ID einer Kreatur, um sie direkt zu rufen.|r\n\n|cffff0000Linksklick, um eine ID einzugeben|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.pet.family"] = "Zufälliger Begleiter nach |cff00ff00FAMILIE|r\n|cffffffffWähle eine Tierfamilie, um ein zufälliges Tier dieses Typs zu rufen.|r\n\n|cffff0000Linksklick, um eine Familie auszuwählen|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.pet.rename"] = "Benenne deinen aktuellen Begleiter um\n|cffffffffÖffnet ein Eingabefeld, um deinem aktiven Tier einen neuen Namen zu geben.|r\n\n|cffff0000Linksklick, um umzubenennen|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.pet.abandon"] = "Begleiter verstoßen\n|cffffffffMit diesem Befehl könnt ihr euren Begleiter verstoßen.|r\n\n|cffff0000Linksklick, um zu verstoßen|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.hunter.ownbutton"] = "Jäger: %s\n|cffffffffDieser Knopf öffnet das Begleitermenü des Jägers.|r\n\n|cffff0000Linksklick zum Öffnen/Schließen|r\n|cffff0000Rechtsklick zum Verschieben|r\n|cff999999(Ausführungsreihenfolge: System)|r",
  ["tips.hunter.pet.stances"] = "Haltungsbefehle\n|cffffffffÖffnet das Haltungsmenü des Begleiters.|r\n\n|cffff0000Linksklick zum Öffnen/Schließen|r\n|cff999999(Ausführungsreihenfolge: System)|r",
