  ["tips.mage.buff.bmana"] = "Mana-Buff|cffffffff\nDiese Schaltfläche aktiviert den Mana-Buff.|r\n\n|cffff0000Linksklicken um Mana-Buff zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.mage.buff.bdps"] = "DPS-Buff|cffffffff\nDiese Schaltfläche aktiviert den DPS-Buff.|r\n\n|cffff0000Linksklicken um DPS-Buff zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
