  ["tips.paladin.caura.bspeed"] = "Speed-Aura|cffffffff\nDiese Schaltfläche aktiviert den Speed-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Speed-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.caura.rfire"] = "Fire-Resist-Aura|cffffffff\nDiese Schaltfläche aktiviert den Fire-Resist-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Fire-Resist-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.caura.rfrost"] = "Frost-Resist-Aura|cffffffff\nDiese Schaltfläche aktiviert den Frost-Resist-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Frost-Resist-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.caura.rshadow"] = "Shadow-Resist-Aura|cffffffff\nDiese Schaltfläche aktiviert den Shadow-Resist-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Shadow-Resist-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.caura.baoe"] = "Damage-Aura|cffffffff\nDiese Schaltfläche aktiviert den Damage-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Damage-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.caura.barmor"] = "Armor-Aura|cffffffff\nDiese Schaltfläche aktiviert den Armor-Aura während des Kampfes.|r\n\n|cffff0000Linksklicken um Armor-Aura zu aktiviern|r\n|cff999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.dps.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.dps.dpsAssist"] = "DPS-Assist|cffffffff\nDiese Schaltfläche aktiviert die DPS-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.dps.dpsAoe"] = "DPS-AOE|cffffffff\nDiese Schaltfläche aktiviert die DPS-AOE-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.dps.dps"] = "DPS|cffffffff\nDiese Strategie macht den Paladin zum Nahkämpfer.\nTank, DPS und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.dps.offheal"] = "OffHeal|cffffffff\nDeaktiviert den DPS-Modus und aktiviert OffHeal,\nDie Bots konzentrieren sich auf Schaden, heilen aber bei Bedarf.\nNur für Paladine.|r\n\n|cffff0000Linksklick, um OffHeal zu aktivieren oder zu deaktivieren|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.paladin.dps.healerdps"] = "HealerDps|cffffffff\nErlaubt dem Heiler, Schaden zu verursachen, wenn es sicher ist.\nDer Bot behält Heilung als höchste Priorität bei und fügt bei geringer Schadensaufnahme DPS ein.\nEmpfohlen für Heiler-Spielweisen (z. B. Heil-Paladin).|r\n\n|cffff0000Left-Click to enable or disable HealerDps|r\n|cf9999999(Execution-Order: Bot)|r",
  ["tips.paladin.tankAssist"] = "Tank-Assist|cffffffff\nDiese Schaltfläche aktiviert die Tank-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Tank-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.paladin.tank"] = "Tank|cffffffff\nDiese Strategie macht den Paladin zum Tank.\nTank, DPS und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Tank ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.heal"] = "Heal|cffffffff\nDiese Strategie macht den Priester zum Heiler.\nShadow und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Heal ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.buff"] = "Buff|cffffffff\nDiese Strategie erlaubt dem Priester die Gruppe zu buffen.|r\n\n|cffff0000Linksklicken um Buffs ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.playbook.master"] = "Playbook|cffffffff\nIm Playbook findet man die Klassen-typischen Strategien.|r\n\n|cffff0000Linksklicken um das Playbook ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: System)|r",
  ["tips.priest.playbook.shadowDebuff"] = "Shadow-Debuff|cffffffff\nDiese Strategie erlaubt dem Priester Shadow-Debuffs während des Kampfes zu verwenden.|r\n\n|cffff0000Linksklicken um Shadow-Debuff ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.playbook.shadowAoe"] = "Shadow-AOE|cffffffff\nDiese Strategie erlaubt dem Priester Shadow-AOE-Spells während des Kampfes zu verwenden.|r\n\n|cffff0000Linksklicken um Shadow-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.playbook.shadow"] = "Shadow|cffffffff\nDiese Strategie erlaubt dem Priester Shadow-Spells während des Kampfes einzustezen.\nShadow und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Shadow ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.playbook.holyheal"] = "Heilig – Heilung|cffffffff\nSchaltet das Playbook auf Heilig (Heilung) um.\nHeilig–Heilung, Schatten und Heilig–DPS schließen sich gegenseitig aus.\nNur eines dieser Playbooks kann aktiv sein.|r\n\n|cffff0000Linksklick, um Heilig–Heilung zu aktivieren/deaktivieren|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.priest.playbook.holydps"] = "Heilig – DPS|cffffffff\nSchaltet das Playbook auf Heilig (DPS) um.\nHeilig–DPS, Schatten und Heilig–Heilung schließen sich gegenseitig aus.\nNur eines dieser Playbooks kann aktiv sein.|r\n\n|cffff0000Linksklick, um Heilig–DPS zu aktivieren/deaktivieren|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.priest.playbook.rshadow"] = "Schattenwiderstand|cffffffff\nAktiviert die Strategie „Schattenwiderstand“.\nDiese Option ist kein Playbook und kann mit anderen Playbooks kombiniert werden.|r\n\n|cffff0000Linksklick, um Schattenwiderstand zu aktivieren/deaktivieren|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.priest.dps.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.dps.dpsAssist"] = "DPS-Assist|cffffffff\nDiese Schaltfläche aktiviert die DPS-Assist-Strategie.\nDPS-AOE, DPS-Assist ('Healer-DPS') und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.dps.dpsDebuff"] = "DPS-Debuff|cffffffff\nDiese Schaltfläche aktiviert die DPS-Debuff-Strategie.|r\n\n|cffff0000Linksklicken um DPS-Debuff ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.dps.dpsAoe"] = "DPS-AOE|cffffffff\nDiese Schaltfläche aktiviert die DPS-AOE-Strategie.\nDPS-AOE, DPS-Assist ('Healer-DPS') und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.dps.dps"] = "DPS|cffffffff\nDiese Schaltfläche aktiviert die DPS-Strategie.|r\n\n|cffff0000Linksklicken um DPS ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.priest.tankAssist"] = "Tank-Assist|cffffffff\nDiese Schaltfläche aktiviert die Tank-Assist-Strategie.\nDPS-AOE, DPS-Assist ('Healer-DPS') und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Tank-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.rogue.dps.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.rogue.dps.dpsAssist"] = "DPS-Assist|cffffffff\nDiese Schaltfläche aktiviert die DPS-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.rogue.dps.dpsAoe"] = "DPS-AOE|cffffffff\nDiese Schaltfläche aktiviert die DPS-AOE-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.rogue.dps.dps"] = "DPS|cffffffff\nDiese Schaltfläche aktiviert die DPS-Strategie.|r\n\n|cffff0000Linksklicken um DPS ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.rogue.dps.stealth"] = "Verstohlenheit|cffffffff\nHält den Schurken möglichst oft verstohlen und bevorzugt verstohlene Eröffnungen.\nKompatibel mit DPS-Modi. Für das Verhalten im Kampf\nverwende |cffffd200Verstohlen (Kampf)|cffffffff.|r\n\n|cffff0000Linksklick zum Aktivieren/Deaktivieren der Verstohlenheit|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.rogue.dps.stealthed"] = "Verstohlen (Kampf)|cffffffff\nBevorzugt Kämpfen in Verstohlenheit; nähert sich verstohlen.\nNutzen verstohlener Eröffnungen; kann DPS pausieren, um erneut zu verstohlenen.\n„Verstohlen (Kampf)“ und DPS/DPS-AOE/DPS-Assist schließen sich aus.\nEs kann nur eine Strategie aktiv sein.|r\n\n|cffff0000Linksklick zum Aktivieren/Deaktivieren|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.rogue.dps.boost"] = "Boost|cffffffff\nAktiviert den Einsatz offensiver Abklingzeiten gemäß der Rotation.\nFunktioniert mit DPS/DPS-AOE/DPS-Assist und Tank-Assist; nicht exklusiv.|r\n\n|cffff0000Linksklick zum Aktivieren/Deaktivieren von Boost|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.rogue.tankAssist"] = "Tank-Assist|cffffffff\nDiese Schaltfläche aktiviert die Tank-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Tank-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
