  ["tips.shaman.playbook.casterAoe"] = "Caster-AOE|cffffffff\nDiese Strategie erlaubt es dem Shamanen Caster-AOE-Spells zu verwenden.|r\n\n|cffff0000Linksklicken um Caster-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.playbook.caster"] = "Caster|cffffffff\nDiese Strategie macht den Shamanen zum Zauberer.\nCaster, Melee und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Caster ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.playbook.meleeAoe"] = "Melee-AOE|cffffffff\nDiese Strategie erlaubt es dem Shamanen Melee-AOE zu verwenden.|r\n\n|cffff0000Linksklicken um Melee-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.playbook.melee"] = "Melee|cffffffff\nDiese Strategie macht den Shamanen zum Nahkämpfer.\nCaster, Melee und Heal schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Melee ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.dps.master"] = "DPS-Control|cffffffff\nMit dieser Steuereinheit legt man die generelle DPS-Strategie fest.|r\n\n|cffff0000Linksklicken um die Steuereinheit ein- oder auszublenden|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.dps.dpsAssist"] = "DPS-Assist|cffffffff\nDiese Schaltfläche aktiviert die DPS-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.dps.dpsAoe"] = "DPS-AOE|cffffffff\nDiese Schaltfläche aktiviert die DPS-AOE-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um DPS-AOE ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
  ["tips.shaman.playbook.cure"] = "Heilen|cffffffff\nAktiviert die Heilungs-Strategie.\nDer Bot wird, wenn möglich, Gifte, Flüche und Krankheiten entfernen.|r\n\n|cffff0000Linksklick, um Heilen zu aktivieren oder zu deaktivieren|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.shaman.dps.healerdps"] = "Heiler-DPS|cffffffff\nAktiviert die Heiler-DPS-Strategie.\nDer Heiler wird Schaden verursachen und sich gleichzeitig weiterhin auf das Heilen konzentrieren.\nHeiler-DPS, DPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann aktiviert sein.|r\n\n|cffff0000Linksklick, um Heiler-DPS zu aktivieren oder zu deaktivieren|r\n|cf9999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.shaman.tankAssist"] = "Tank-Assist|cffffffff\nDiese Schaltfläche aktiviert die Tank-Assist-Strategie.\nDPS-AOE, DPS-Assist und Tank-Assist schließen sich gegenseitig aus.\nNur eine dieser Strategien kann zeitgleich aktiviert sein.|r\n\n|cffff0000Linksklicken um Tank-Assist ein- oder auszuschalten|r\n|cf9999999(Ausführreihenfolge: Bot)|r",
