  ["tips.every.autogear"] = "Auto-Ausrüstung|cffffffff\nRüstet diesen Bot automatisch aus basierend auf\ndeinen AutoGear-Grenzen (Qualität / GearScore).|r\n\n|cffff0000Linksklick zum Starten der Auto-Ausrüstung|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.every.autogearpopup"] = "Autogear auf %s starten?",
  ["tips.every.maintenance"] = "Wartung|cffffffff\nAktiviere den Bot, um alle verfügbaren Zauber und Fertigkeiten zu erlernen,\nVerbrauchsgüter aufzufüllen, Ausrüstung zu verzaubern und zu reparieren.|r\n\n|cffff0000Linksklick, um die Wartung zu starten|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.every.summon"] = "Summon|cffffffff\nDiese Schaltfläche beschwört den Bot an deine Position.|r\n\n|cffff0000Linksklicken um den Bot zu beschwören|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.uninvite"] = "Uninvite|cffffffff\nDiese Schaltfläche entfernt den Bot aus der Gruppe.|r\n\n|cffff0000Linksklicken um den Bot zu entfernen|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.invite"] = "Invite|cffffffff\nDiese Schaltfläche lädt den Bot in die Gruppe ein.|r\n\n|cffff0000Linksklicken um den Bot einzuladen|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.strategy.food"] = "Food|cffffffff\nDiese Schaltfläche aktiviert oder deaktiviert die Food-Strategie.|r\n\n|cffff0000Linksklicken um Food ein- oder auszuschalten|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.strategy.loot"] = "Loot|cffffffff\nDiese Schaltfläche aktiviert oder deaktiviert die Loot-Strategie.|r\n\n|cffff0000Linksklicken um Loot ein- oder auszuschalten|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.strategy.gather"] = "Sammeln|cffffffff\nDiese Schaltfläche aktiviert oder deaktiviert die Sammel-Strategie.|r\n\n|cffff0000Linksklicken um Sammeln ein- oder auszuschalten|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.inventory"] = "Inventar|cffffffff\nDiese Schaltfläche öffnet oder schließt das Inventar des Bots.|r\n\n|cffff0000Linksklicken um das Inventar zu öffnen oder schließen|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.spellbook"] = "Zauberbuch|cffffffff\nDiese Schaltfläche öffnet oder schließt das Zauberbuch des Bots.\nLinksklicken um einen Zauber direkt zu verwenden.\nRechtsklicken um einen Zauber als Macro in die Hotbars zu legen.|r\n\n|cffff0000Linksklicken um das Zauberbuch zu öffnen oder schließen|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.talent"] = "Talente|cffffffff\nDiese Schaltfläche öffnet oder schließt die Talente des Bots.\nDie Talente öffnen zeitverzögert, damit das System die Punkte laden kann.|r\n\n|cffff0000Linksklicken um das Talente zu öffnen oder schließen|r\n|cff999999(Execution-Order: Bot)|r",
  ["tips.every.wipe"] = "Wipe|cffffffff\nSetzt den Bot vollständig zurück, indem er getötet und wiederbelebt wird,\nnützlich zum Zurücksetzen seines Zustands (Position, Gesundheit, Mana usw.).|r\n\n|cffff0000Linksklick: sendet den Wipe-Befehl an den ausgewählten Bot|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.every.settalent"] = "Talente auswählen|cffffffff\nZeigt ein Menü der verfügbaren Spezialisierungen (PvE/PvP) für den ausgewählten Bot an.\nDie sekundäre Spezialisierung wird auf Stufe 40 freigeschaltet.|r\n\n|cffff0000Linksklick, um den Talentvorlagen-Selektor des Bots ein-/auszublenden|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
  ["tips.every.combat"] = "Kampf|cffffffff\nÖffnet die Kampfstrategie- und Timing‑Befehle für diesen Bot.|r\n|cffff0000Linksklick zum Öffnen oder Schließen|r\n|cff999999(Ausführungsreihenfolge: Bot)|r",
