  ["tips.rtsc.spot"] = "Location-Storage\n|cffffffffLinksklicken um die Bots zum gespeicherten Standort zu entsenden.\nRechtsklicken um den gespeicherten Standort zu löschen.|r\n\n|cffff0000Linksklicken um die Bots zu entsenden|r\n|cff999999(Ausführreihenfolge: Raid, Party)|r\n\n|cffff0000Rechtsklicken um den Standort zu löschen|r\n|cff999999(Ausführreihenfolge: System)|r",
